 1	import { Button, Card, Flex, FlexItem, Text, TextVariants, Tooltip } from '@patternfly/react-core';
 2	import { CompressIcon, ExpandIcon, InfoAltIcon } from '@patternfly/react-icons';
 3	import * as React from 'react';
 4	
 5	import { useTranslation } from 'react-i18next';
 6	import './netflow-overview-panel.css';
 7	
 8	export interface NetflowOverviewPanelProps {
 9	  doubleWidth: boolean;
10	  bodyClassName: string;
11	  title: string;
12	  titleTooltip?: string;
13	  kebab?: JSX.Element;
14	  onClick?: () => void;
15	  focusOn?: (id?: string) => void;
16	  isSelected?: boolean;
17	  isFocus?: boolean;
18	  id?: string;
19	}
20	
21	export const NetflowOverviewPanel: React.FC<NetflowOverviewPanelProps> = ({
22	  id,
23	  doubleWidth,
24	  bodyClassName,
25	  title,
26	  titleTooltip,
27	  kebab,
28	  children,
29	  onClick,
30	  focusOn,
31	  isFocus
32	}) => {
33	  const { t } = useTranslation('plugin__netobserv-plugin');
34	
35	  return (
36	    <FlexItem id={id} className={`overview-flex-item center ${doubleWidth ? 'full' : ''}`}>
37	      <Card isFullHeight isSelectable={onClick !== undefined} className="overview-card" onClick={onClick}>
38	        <Flex className="overview-card-content" direction={{ default: 'column' }} gap={{ default: 'gapNone' }}>
39	          <FlexItem>
40	            <Flex direction={{ default: 'row' }}>
41	              <FlexItem flex={{ default: 'flex_1' }} className="overview-title">
42	                <Text component={TextVariants.h3}>
43	                  {title}
44	                  {titleTooltip && (
45	                    <Tooltip content={titleTooltip}>
46	                      <InfoAltIcon />
47	                    </Tooltip>
48	                  )}
49	                </Text>
50	              </FlexItem>
51	              {focusOn !== undefined && (
52	                <FlexItem className="overview-expand-button-container">
53	                  <Tooltip
54	                    content={
55	                      <Text component={TextVariants.p}>
56	                        {isFocus ? t('Show all graphs') : t('Focus on this graph')}
57	                      </Text>
58	                    }
59	                  >
60	                    <Button
61	                      variant="plain"
62	                      className="overview-expand-button"
63	                      icon={isFocus ? <CompressIcon /> : <ExpandIcon />}
64	                      onClick={() => focusOn(id)}
65	                    />
66	                  </Tooltip>
67	                </FlexItem>
68	              )}
69	              {onClick === undefined && <FlexItem>{kebab}</FlexItem>}
70	            </Flex>
71	          </FlexItem>
72	          <FlexItem flex={{ default: 'flex_1' }} className={bodyClassName}>
73	            {children}
74	          </FlexItem>
75	        </Flex>
76	      </Card>
77	    </FlexItem>
78	  );
79	};

