 1	import { render } from '@testing-library/react';
 2	import * as React from 'react';
 3	
 4	import { MetricType } from '../../../../model/flow-query';
 5	import { metrics } from '../../../__tests-data__/metrics';
 6	import { SamplePanel } from '../../../__tests-data__/panels';
 7	import { MetricsGraph, MetricsGraphProps } from '../../../metrics/metrics-graph';
 8	import { NetflowOverviewPanel } from '../netflow-overview-panel';
 9	
10	describe('<NetflowOverviewPanel />', () => {
11	  const panelProps = {
12	    doubleWidth: false,
13	    bodyClassName: 'overview-panel-body',
14	    title: 'title',
15	    kebabItems: []
16	  };
17	  const contentProps: MetricsGraphProps = {
18	    id: SamplePanel.id,
19	    metricType: 'Bytes' as MetricType,
20	    metricFunction: 'avg',
21	    metrics: metrics.map(m => ({ ...m, shortName: 'whatever', fullName: 'whatever', isInternal: false })),
22	    limit: 5,
23	    tooltipsTruncate: true
24	  };
25	
26	  it('should render component', async () => {
27	    const { container } = render(<NetflowOverviewPanel {...panelProps} />);
28	    expect(container.firstChild).toBeTruthy();
29	  });
30	
31	  it('should render content', async () => {
32	    const { container } = render(
33	      <NetflowOverviewPanel {...panelProps}>
34	        <MetricsGraph {...contentProps} />
35	      </NetflowOverviewPanel>
36	    );
37	    expect(container.querySelector('.pf-v6-c-card')).toBeTruthy();
38	  });
39	});

